// File generated by AI effectively

// FieldRenderer is a function type that takes a field value and returns a gomponents node.
type FieldRenderer func(value any) g.Node

// RowLinkGenerator is a function type that takes an item and returns a URL path for navigation.
type RowLinkGenerator[T any] func(item T) string

// PaginationURLGenerator is a function type that generates a URL for pagination with the given cursor.
type PaginationURLGenerator func(cursor string) string

// CreateStatusFilter creates a status filter toggle that uses the search endpoint.
func CreateStatusFilter(searchEndpoint, currentStatus, tableID string) g.Node {
	statusOptions := []struct {
		Value string
		Label string
	}{
		{Value: "submitted", Label: "Submitted"},
		{Value: "approved", Label: "Approved"},
	}

	var optionNodes []g.Node
	for i := range statusOptions {
		opt := &statusOptions[i]
		optionNodes = append(optionNodes,
			ghtml.Option(
				g.If(opt.Value == currentStatus, ghtml.Selected()),
				g.Attr("value", opt.Value),
				g.Text(opt.Label),
			),
		)
	}

	selectID := fmt.Sprintf("%s-status-filter", tableID)

	return ghtml.Div(
		ghtml.Class("flex items-center gap-2 mr-4"),
		ghtml.Label(
			ghtml.Class("text-sm text-gray-600 whitespace-nowrap"),
			g.Text("Status:"),
		),
		ghtml.Select(
			ghtml.Class("px-2 py-1 text-sm border border-gray-300 rounded-md bg-white text-gray-900 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"),
			g.Attr("name", "status"),
			g.Attr("id", selectID),
			g.Attr("hx-get", searchEndpoint),
			g.Attr("hx-target", "#search-results"),
			g.Attr("hx-swap", "innerHTML"),
			g.Attr("hx-push-url", "true"),
			g.Attr("hx-trigger", "change"),
			// Include the search input value to preserve search query
			g.Attr("hx-include", "#search"),
			g.Attr("hx-vals", "js:{status: this.value}"),
			g.Group(optionNodes),
		),
	)
}

// CreatePageSizeSelector creates a page size selector dropdown that uses the search endpoint.
func CreatePageSizeSelector(searchEndpoint string, currentLimit uint8, tableID string) g.Node {
	pageSizeOptions := []uint8{25, 50, 100, 250}

	var optionNodes []g.Node
	for _, size := range pageSizeOptions {
		optionNodes = append(optionNodes,
			ghtml.Option(
				g.If(size == currentLimit, ghtml.Selected()),
				g.Attr("value", fmt.Sprintf("%d", size)),
				g.Text(fmt.Sprintf("%d", size)),
			),
		)
	}

	selectID := fmt.Sprintf("%s-page-size", tableID)

	return ghtml.Div(
		ghtml.Class("flex items-center gap-2 mr-4"),
		ghtml.Label(
			ghtml.Class("text-sm text-gray-600 whitespace-nowrap"),
			g.Text("Show:"),
		),
		ghtml.Select(
			ghtml.Class("px-2 py-1 text-sm border border-gray-300 rounded-md bg-white text-gray-900 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"),
			g.Attr("name", "limit"),
			g.Attr("id", selectID),
			g.Attr("hx-get", searchEndpoint),
			g.Attr("hx-target", "#search-results"),
			g.Attr("hx-swap", "innerHTML"),
			g.Attr("hx-push-url", "true"),
			g.Attr("hx-trigger", "change"),
			// Include the search input value to preserve search query
			g.Attr("hx-include", "#search"),
			g.Attr("hx-vals", "js:{limit: this.value}"),
			g.Group(optionNodes),
		),
	)
}

// TableOptions holds configuration options for the table.
type TableOptions[T any] struct {
	FieldRenderers         map[string]FieldRenderer
	FieldReplacements      map[string]string
	Palette                *design.Palette
	RowLinkGenerator       RowLinkGenerator[T]
	Pagination             *filtering.Pagination
	PaginationURLGenerator PaginationURLGenerator
	DeepLinkURLGenerator   PaginationURLGenerator // Optional: generates main page URL for deep linking (hx-push-url)
	TableID                string
	CSSClasses             string
	PaginationHTMXTarget   string
	Fields                 []string
}

// DefaultFieldRenderer provides default rendering for common types.
func DefaultFieldRenderer(value any) g.Node {
	if value == nil {
		return g.Text("-")
	}

	switch v := value.(type) {
	case time.Time:
		if v.IsZero() {
			return g.Text("-")
		}
		return g.Text(v.Format("2006-01-02 15:04:05"))
	case *time.Time:
		if v == nil || v.IsZero() {
			return g.Text("-")
		}
		return g.Text(v.Format("2006-01-02 15:04:05"))
	case string:
		if v == "" {
			return g.Text("-")
		}
		return g.Text(v)
	case *string:
		if v == nil || *v == "" {
			return g.Text("-")
		}
		return g.Text(*v)
	case fmt.Stringer:
		str := v.String()
		if str == "" {
			return g.Text("-")
		}
		return g.Text(str)
	default:
		return g.Text(fmt.Sprintf("%v", v))
	}
}

// extractFields uses reflection to get field information from a struct.
func extractFields(item any) ([]*fieldInfo, error) {
	var fields []*fieldInfo

	v := reflect.ValueOf(item)
	if !v.IsValid() {
		return nil, fmt.Errorf("invalid value")
	}

	// Handle pointers
	if v.Kind() == reflect.Ptr {
		if v.IsNil() {
			return nil, fmt.Errorf("nil pointer")
		}
		v = v.Elem()
	}

	if v.Kind() != reflect.Struct {
		return nil, fmt.Errorf("expected struct or pointer to struct, got %s", v.Kind())
	}

	t := v.Type()

	for i := 0; i < t.NumField(); i++ {
		field := t.Field(i)

		// Skip unexported fields
		if !field.IsExported() {
			continue
		}

		// Extract JSON tag
		jsonTag := field.Tag.Get("json")
		if jsonTag == "" || jsonTag == "-" {
			// Skip fields without JSON tags or with "-" tag
			continue
		}

		// Parse JSON tag (handle "fieldName,omitempty" format)
		jsonName := strings.Split(jsonTag, ",")[0]
		if jsonName == "" || jsonName == "-" {
			continue
		}

		// Create a display name (convert CamelCase to Title Case)
		displayName := camelCaseToTitleCase(field.Name)

		fields = append(fields, &fieldInfo{
			Name:        jsonName,   // Use JSON tag name
			GoFieldName: field.Name, // Keep Go struct field name for reflection
			DisplayName: displayName,
			Type:        field.Type,
		})
	}

	return fields, nil
}

// applyFieldOrdering applies the specified field ordering to the fields slice.
// If customOrder is nil or empty, uses automatic ordering (MealPlanTaskID first, timestamps last).
// If customOrder is provided, only fields in that list will be included, in that order.
func applyFieldOrdering(fields []*fieldInfo, customOrder []string, replacements map[string]string) []*fieldInfo {
	// If no custom order specified, use automatic ordering
	if len(customOrder) == 0 {
		fields = sortFields(fields)
	} else {
		// Create a map of field name to field info for quick lookup
		fieldMap := make(map[string]*fieldInfo)
		for _, field := range fields {
			fieldMap[field.Name] = field
		}

		// Build result in the specified order
		result := make([]*fieldInfo, 0, len(customOrder))
		for _, name := range customOrder {
			if field, exists := fieldMap[name]; exists {
				result = append(result, field)
			}
		}
		fields = result
	}

	// Apply field replacements to display names
	if len(replacements) > 0 {
		for i := range fields {
			if customName, exists := replacements[fields[i].Name]; exists {
				fields[i].DisplayName = customName
			}
		}
	}

	return fields
}

// Table creates a generic HTML table from a slice of structs.
// It returns a wrapper div that includes both the table and pagination controls.
func Table[T any](data []T, options *TableOptions[T]) (g.Node, error) {
	if options == nil {
		options = &TableOptions[T]{}
	}

	// Get palette (use standard if not provided)
	palette := options.Palette
	if palette == nil {
		palette = &design.StandardPalette
	}

	var tableNode g.Node

	if len(data) == 0 {
		tableNode = createEmptyTable(options)
	} else {
		// Extract field information from the first item
		fields, extractErr := extractFields(data[0])
		if extractErr != nil {
			return nil, fmt.Errorf("failed to extract fields: %w", extractErr)
		}

		// Apply field ordering and replacements
		fields = applyFieldOrdering(fields, options.Fields, options.FieldReplacements)

		if len(fields) == 0 {
			tableNode = createEmptyTable(options)
		} else {
			// Build table classes
			tableClasses := buildTableClasses(options.CSSClasses)

			tableAttrs := []g.Node{ghtml.Class(tableClasses)}
			if options.TableID != "" {
				tableAttrs = append(tableAttrs, ghtml.ID(options.TableID))
			}

			tableNode = ghtml.Table(
				append(tableAttrs,
					// Table header
					createTableHeader(fields, palette),
					// Table body
					createTableBody(data, fields, options),
				)...,
			)
		}
	}

	// Create pagination controls if pagination info is provided
	paginationNode := CreatePaginationControls(options, palette)

	// If there's pagination, wrap both table and pagination in a container
	if paginationNode != nil {
		return ghtml.Div(
			ghtml.Class("space-y-4"),
			tableNode,
			paginationNode,
		), nil
	}

	return tableNode, nil
}

// fieldInfo holds information about a struct field.
type fieldInfo struct {
	Type        reflect.Type
	Name        string // JSON tag name (e.g., "zipCode")
	GoFieldName string // Go struct field name (e.g., "ZipCode")
	DisplayName string
}

// sortFields sorts the fields with custom ordering:
// - MealPlanTaskID field first.
// - CreatedAt, LastUpdatedAt, ArchivedAt fields last (in that order).
// - All other fields in their original order in between.
func sortFields(fields []*fieldInfo) []*fieldInfo {
	// Define priority fields (using JSON tag names - PascalCase for protobuf)
	priorityFirst := "MealPlanTaskID"
	priorityLast := []string{"CreatedAt", "LastUpdatedAt", "ArchivedAt"}

	// Create a map for quick lookup of priority last fields
	lastFieldsMap := make(map[string]int)
	for i, name := range priorityLast {
		lastFieldsMap[name] = i
	}

	// Separate fields into categories
	var idField []*fieldInfo
	var regularFields []*fieldInfo
	lastFields := make([]*fieldInfo, len(priorityLast))
	lastFieldsFound := make([]bool, len(priorityLast))

	for _, field := range fields {
		if field.Name == priorityFirst {
			idField = append(idField, field)
		} else if idx, isLast := lastFieldsMap[field.Name]; isLast {
			lastFields[idx] = field
			lastFieldsFound[idx] = true
		} else {
			regularFields = append(regularFields, field)
		}
	}

	// Build the result slice in order
	result := make([]*fieldInfo, 0, len(fields))

	// Add MealPlanTaskID first
	result = append(result, idField...)

	// Add regular fields
	result = append(result, regularFields...)

	// Add last fields that were found (in priority order)
	for i, found := range lastFieldsFound {
		if found {
			result = append(result, lastFields[i])
		}
	}

	return result
}

// createTableHeader creates the table header row.
func createTableHeader(fields []*fieldInfo, palette *design.Palette) g.Node {
	var headerCells []g.Node

	for _, field := range fields {
		headerCells = append(headerCells,
			ghtml.Th(
				ghtml.Class(fmt.Sprintf("px-4 py-2 text-left text-sm font-semibold %s uppercase tracking-wide border-b-2 %s bg-gray-50",
					design.TextColor(design.Color{Value: "gray-800"}), // Darker text for better contrast
					design.BorderColor(palette.Primary),               // Primary color border for accent
				)),
				g.Text(field.DisplayName),
			),
		)
	}

	return ghtml.THead(
		ghtml.Class("bg-gray-50"),
		ghtml.Tr(headerCells...),
	)
}

// createTableBody creates the table body with data rows.
func createTableBody[T any](data []T, fields []*fieldInfo, options *TableOptions[T]) g.Node {
	var rows []g.Node

	for i, item := range data {
		var cells []g.Node

		v := reflect.ValueOf(item)
		if v.Kind() == reflect.Ptr {
			if v.IsNil() {
				continue // Skip nil pointers
			}
			v = v.Elem()
		}

		for _, field := range fields {
			// Use GoFieldName for reflection lookup
			fieldValue := v.FieldByName(field.GoFieldName)
			if !fieldValue.IsValid() {
				// If field doesn't exist but there's a custom renderer, pass the whole item
				if options.FieldRenderers != nil {
					if _, hasRenderer := options.FieldRenderers[field.Name]; hasRenderer {
						cells = append(cells, createTableCell(item, field.Name, options))
						continue
					}
				}
				cells = append(cells, createTableCell(nil, field.Name, options))
				continue
			}

			var cellValue any
			if fieldValue.CanInterface() {
				cellValue = fieldValue.Interface()
			}

			cells = append(cells, createTableCell(cellValue, field.Name, options))
		}

		// Alternate row colors with better contrast
		rowClass := "bg-white hover:bg-blue-50"
		if i%2 == 1 {
			rowClass = "bg-gray-50 hover:bg-blue-50"
		}

		// If RowLinkGenerator is provided, make the row clickable with HTMX
		var linkURL string
		if options.RowLinkGenerator != nil {
			linkURL = options.RowLinkGenerator(item)
			if linkURL != "" {
				// Add cursor-pointer to the row class when clickable
				rowClass += " cursor-pointer"
			}
		}

		// Build the row with or without HTMX navigation
		if linkURL != "" {
			rows = append(rows, ghtml.Tr(
				ghtml.Class(fmt.Sprintf("%s transition-colors duration-150", rowClass)),
				// HTMX attributes for navigation
				g.Attr("hx-get", linkURL),
				g.Attr("hx-target", "body"),
				g.Attr("hx-swap", "innerHTML"),
				g.Attr("hx-push-url", "true"),
				// Styling and accessibility
				g.Attr("style", "cursor: pointer;"),
				g.Attr("title", "Click to view details"),
				g.Attr("role", "button"),
				g.Attr("tabindex", "0"),
				g.Group(cells),
			))
		} else {
			rows = append(rows, ghtml.Tr(
				ghtml.Class(fmt.Sprintf("%s transition-colors duration-150", rowClass)),
				g.Group(cells),
			))
		}
	}

	return ghtml.TBody(
		ghtml.Class("bg-white divide-y divide-gray-200"),
		g.Group(rows),
	)
}

// createTableCell creates a single table cell.
func createTableCell[T any](value any, fieldName string, options *TableOptions[T]) g.Node {
	var content g.Node

	// Use custom renderer if available
	if options.FieldRenderers != nil {
		if renderer, exists := options.FieldRenderers[fieldName]; exists {
			content = renderer(value)
		} else {
			content = DefaultFieldRenderer(value)
		}
	} else {
		content = DefaultFieldRenderer(value)
	}

	return ghtml.Td(
		ghtml.Class("px-4 py-3 whitespace-nowrap text-sm text-gray-900"),
		content,
	)
}

// createEmptyTable creates a table with a "no data" message.
func createEmptyTable[T any](options *TableOptions[T]) g.Node {
	tableClasses := buildTableClasses(options.CSSClasses)

	tableAttrs := []g.Node{ghtml.Class(tableClasses)}
	if options.TableID != "" {
		tableAttrs = append(tableAttrs, ghtml.ID(options.TableID))
	}

	return ghtml.Table(
		append(tableAttrs,
			ghtml.TBody(
				ghtml.Tr(
					ghtml.Td(
						ghtml.Class("px-4 py-12 text-center text-sm text-gray-500 bg-gray-50"),
						ghtml.ColSpan("100%"),
						g.Text("No data available"),
					),
				),
			),
		)...,
	)
}

// buildTableClasses constructs the CSS classes for the table.
func buildTableClasses(customClasses string) string {
	baseClasses := "min-w-full divide-y divide-gray-200 shadow-lg rounded-lg overflow-hidden border border-gray-200"
	if customClasses != "" {
		return fmt.Sprintf("%s %s", baseClasses, customClasses)
	}
	return baseClasses
}

// commonInitialisms is a list of common initialisms that should not be split
// Add additional initialisms here as needed.
var commonInitialisms = []string{
	"MealPlanTaskID",
	"API",
	"URI",
	"URL",
	"HTTP",
	"HTTPS",
	"JSON",
	"XML",
	"SQL",
	"DB",
	"CPU",
	"RAM",
	"UUID",
	"HTML",
	"CSS",
	"JS",
	"UI",
	"UX",
	"OS",
}

// camelCaseToTitleCase converts CamelCase to Title Case with spaces
// It handles common initialisms (like MealPlanTaskID, API, etc.) as single units.
func camelCaseToTitleCase(s string) string {
	if s == "" {
		return s
	}

	// Check for initialisms at the start of the string
	for _, initialism := range commonInitialisms {
		if strings.HasPrefix(s, initialism) {
			// If the string is exactly the initialism, return it as-is
			if len(s) == len(initialism) {
				return initialism
			}
			// If there's more after the initialism, process the rest
			rest := camelCaseToTitleCase(s[len(initialism):])
			if rest != "" {
				return initialism + " " + rest
			}
			return initialism
		}
	}

	var result strings.Builder
	result.WriteByte(s[0])

	for i := 1; i < len(s); i++ {
		// Check if we're at the start of an initialism
		foundInitialism := false
		for _, initialism := range commonInitialisms {
			if i+len(initialism) > len(s) || s[i:i+len(initialism)] != initialism {
				continue
			}
			result.WriteByte(' ')
			result.WriteString(initialism)
			i += len(initialism) - 1 // -1 because the loop will increment
			foundInitialism = true
			break
		}

		if !foundInitialism {
			if s[i] >= 'A' && s[i] <= 'Z' {
				result.WriteByte(' ')
			}
			result.WriteByte(s[i])
		}
	}

	return result.String()
}

// CreatePaginationControls creates pagination controls if pagination information is available.
func CreatePaginationControls[T any](options *TableOptions[T], palette *design.Palette) g.Node {
	if options.Pagination == nil {
		return nil
	}

	pagination := options.Pagination
	hasMore := pagination.Cursor != ""

	// Build pagination info text
	// Show the page size (MaxResponseSize) as the number being shown, not the total filtered count
	var infoText string
	if pagination.FilteredCount > 0 || pagination.TotalCount > 0 {
		pageSize := int(pagination.MaxResponseSize)
		if pagination.FilteredCount == pagination.TotalCount {
			// No filters applied, show page size and total count
			infoText = fmt.Sprintf("Showing %d of %d total", pageSize, pagination.TotalCount)
		} else {
			// Filters applied, show page size, filtered count, and total count
			infoText = fmt.Sprintf("Showing %d of %d filtered (of %d total)", pageSize, pagination.FilteredCount, pagination.TotalCount)
		}
	}

	// If there's no more data and no counts to show, don't render pagination
	if !hasMore && infoText == "" {
		return nil
	}

	// Determine HTMX target
	htmxTarget := options.PaginationHTMXTarget
	if htmxTarget == "" {
		htmxTarget = "#search-results"
	}

	var rightButtons []g.Node

	// Add "Load More" button if there's a next cursor
	if hasMore && options.PaginationURLGenerator != nil {
		nextURL := options.PaginationURLGenerator(pagination.Cursor)
		if nextURL != "" {
			// Ensure cursor is in the URL (the generator should handle this, but we'll add it if missing)
			parsedURL, parseErr := url.Parse(nextURL)
			if parseErr == nil {
				query := parsedURL.Query()
				// Only add cursor if it's not already present
				if query.Get("cursor") == "" {
					query.Set("cursor", pagination.Cursor)
				}
				parsedURL.RawQuery = query.Encode()
				nextURL = parsedURL.String()
				// If URL parsing fails, append cursor as query param
			} else if !strings.Contains(nextURL, "cursor=") {
				if strings.Contains(nextURL, "?") {
					nextURL += "&cursor=" + url.QueryEscape(pagination.Cursor)
				} else {
					nextURL += "?cursor=" + url.QueryEscape(pagination.Cursor)
				}
			}

			// Use deep link URL for hx-push-url if available, otherwise use the request URL
			pushURL := nextURL
			if options.DeepLinkURLGenerator != nil {
				pushURL = options.DeepLinkURLGenerator(pagination.Cursor)
			}

			rightButtons = append(rightButtons,
				ghtml.Button(
					ghtml.Class(fmt.Sprintf("px-4 py-2 text-sm font-medium rounded-md %s %s hover:%s focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-%s transition-colors",
						design.TextColor(design.Color{Value: "white"}),
						design.Background(palette.Primary),
						design.Background(design.Color{Value: palette.Primary.Value + "-700"}),
						palette.Primary.Value,
					)),
					g.Attr("hx-get", nextURL),
					g.Attr("hx-target", htmxTarget),
					g.Attr("hx-swap", "innerHTML"),
					g.Attr("hx-push-url", pushURL),
					g.Text("Load More"),
				),
			)
		}
	}

	// Build children array with info text and right buttons
	var children []g.Node

	// Add info text
	if infoText != "" {
		children = append(children,
			ghtml.Div(
				ghtml.Class("text-sm text-gray-600"),
				g.Text(infoText),
			),
		)
	}

	// Add right buttons (Load More)
	if len(rightButtons) > 0 {
		children = append(children, ghtml.Div(
			ghtml.Class("flex items-center gap-2"),
			g.Group(rightButtons),
		))
	}

	// If there are no children, don't render anything
	if len(children) == 0 {
		return nil
	}

	// Create pagination container with info and right buttons
	return ghtml.Div(
		ghtml.Class("flex justify-between items-center mt-4 pt-4 border-t border-gray-200"),
		g.Group(children),
	)
}
